import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import { phieuTamTruAPI, phongAPI } from '../services/api';

const normalizeName = value => value.trim().replace(/\s+/g, ' ');
const isValidName = value => {
  const normalized = normalizeName(value);
  return normalized.length >= 2 && normalized.length <= 100 && !/\d/.test(normalized);
};
const isValidPhone = value => value === '' || /^\d{10,11}$/.test(value);

export default function PhieuTamTru() {
  const [phieus, setPhieus] = useState([]);
  const [phongs, setPhongs] = useState([]);
  const [form, setForm] = useState({
    maPhong: '',
    hoTen: '',
    soDienThoai: '',
    ngaySinh: '',
    diaChiThuongTru: '',
    ngayBatDau: '',
  });
  const [tab, setTab] = useState('list');
  const [submitting, setSubmitting] = useState(false);

  const set = (key, value) => setForm(current => ({ ...current, [key]: value }));

  useEffect(() => {
    phieuTamTruAPI.layCuaToi().then(res => setPhieus(res.data.data || []));
    phongAPI.layPhongCuaToi().then(res => setPhongs(res.data.data || []));
  }, []);

  const handleSubmit = async e => {
    e.preventDefault();

    const hoTen = normalizeName(form.hoTen);

    if (!isValidName(hoTen)) {
      toast.error('Ho ten phai tu 2-100 ky tu va khong duoc chua so');
      return;
    }

    if (!isValidPhone(form.soDienThoai)) {
      toast.error('So dien thoai phai gom 10 hoac 11 chu so');
      return;
    }

    if (form.ngaySinh && new Date(form.ngaySinh) > new Date()) {
      toast.error('Ngay sinh khong duoc lon hon ngay hien tai');
      return;
    }

    setSubmitting(true);
    try {
      await phieuTamTruAPI.tao({
        ...form,
        hoTen,
        maPhong: parseInt(form.maPhong, 10),
      });
      toast.success('Tao phieu tam tru thanh cong');
      const res = await phieuTamTruAPI.layCuaToi();
      setPhieus(res.data.data || []);
      setForm({
        maPhong: '',
        hoTen: '',
        soDienThoai: '',
        ngaySinh: '',
        diaChiThuongTru: '',
        ngayBatDau: '',
      });
      setTab('list');
    } catch (error) {
      toast.error(error.response?.data?.message || 'That bai');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="container page-wrapper">
      <h1 className="section-title">Phieu tam tru</h1>
      <p className="section-subtitle">Tao va quan ly phieu dang ky tam tru</p>

      <div className="tabs">
        {[['list', 'Danh sach'], ['new', 'Tao phieu moi']].map(([key, label]) => (
          <div key={key} className={`tab ${tab === key ? 'active' : ''}`} onClick={() => setTab(key)}>
            {label}
          </div>
        ))}
      </div>

      {tab === 'list' && (
        phieus.length === 0 ? (
          <div className="empty-state">
            <div className="empty-state-icon">📄</div>
            <p>Chua co phieu tam tru nao.</p>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            {phieus.map(phieu => (
              <div key={phieu.maPhieuTamTru} className="card">
                <div className="card-body">
                  <div style={{ display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', gap: 12 }}>
                    <div>
                      <div style={{ fontWeight: 700, fontSize: 16 }}>#{phieu.maPhieuTamTru} - {phieu.hoTen}</div>
                      <div style={{ color: 'var(--text-muted)', fontSize: 13, marginTop: 4 }}>
                        Phong: {phieu.tenPhong} | Dia chi: {phieu.diaChiThuongTru}
                      </div>
                      <div style={{ color: 'var(--text-muted)', fontSize: 12, marginTop: 4 }}>
                        Bat dau: {phieu.ngayBatDau} | Ngay sinh: {phieu.ngaySinh}
                      </div>
                    </div>
                    <button
                      className="btn btn-outline btn-sm"
                      onClick={() => {
                        const content = `PHIEU DANG KY TAM TRU\n\nHo ten: ${phieu.hoTen}\nNgay sinh: ${phieu.ngaySinh}\nDia chi thuong tru: ${phieu.diaChiThuongTru}\nSo dien thoai: ${phieu.soDienThoai}\nPhong: ${phieu.tenPhong}\nNgay bat dau tam tru: ${phieu.ngayBatDau}`;
                        const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
                        const url = URL.createObjectURL(blob);
                        const a = document.createElement('a');
                        a.href = url;
                        a.download = `phieu-tam-tru-${phieu.maPhieuTamTru}.txt`;
                        a.click();
                      }}
                    >
                      Tai ve
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )
      )}

      {tab === 'new' && (
        <div style={{ maxWidth: 600 }}>
          <div className="card">
            <div className="card-header">Tao phieu dang ky tam tru</div>
            <div className="card-body">
              <div className="alert alert-info">Thong tin nen trung khop voi CCCD da xac thuc.</div>

              <form onSubmit={handleSubmit}>
                <div className="form-group">
                  <label className="form-label">Chon phong *</label>
                  <select className="form-control" required value={form.maPhong} onChange={e => set('maPhong', e.target.value)}>
                    <option value="">-- Chon phong --</option>
                    {phongs.map(phong => <option key={phong.maPhong} value={phong.maPhong}>{phong.title}</option>)}
                  </select>
                </div>

                <div className="grid-2">
                  <div className="form-group">
                    <label className="form-label">Ho ten *</label>
                    <input className="form-control" required maxLength={100} value={form.hoTen} onChange={e => set('hoTen', e.target.value)} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">So dien thoai</label>
                    <input
                      className="form-control"
                      inputMode="numeric"
                      pattern="[0-9]{10,11}"
                      maxLength={11}
                      value={form.soDienThoai}
                      onChange={e => set('soDienThoai', e.target.value.replace(/\D/g, ''))}
                    />
                  </div>
                </div>

                <div className="grid-2">
                  <div className="form-group">
                    <label className="form-label">Ngay sinh</label>
                    <input className="form-control" type="date" value={form.ngaySinh} onChange={e => set('ngaySinh', e.target.value)} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Ngay bat dau tam tru *</label>
                    <input className="form-control" type="date" required value={form.ngayBatDau} onChange={e => set('ngayBatDau', e.target.value)} />
                  </div>
                </div>

                <div className="form-group">
                  <label className="form-label">Dia chi thuong tru</label>
                  <input className="form-control" value={form.diaChiThuongTru} onChange={e => set('diaChiThuongTru', e.target.value)} />
                </div>

                <button type="submit" className="btn btn-primary btn-block btn-lg" disabled={submitting}>
                  {submitting ? 'Dang tao...' : 'Tao phieu tam tru'}
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
